fn call_fl(name: &str, xbits: u64, mode: i32, width: u32) -> u64 {
    let xd = f64::from_bits(xbits);
    let xf = f32::from_bits(xbits as u32);
    unsafe {
        match name {
            "fromfp" => fl::fromfp(xd, mode, width) as u64,
            "fromfpx" => fl::fromfpx(xd, mode, width) as u64,
            "fromfpf" => fl::fromfpf(xf, mode, width) as u64,
            "fromfpxf" => fl::fromfpxf(xf, mode, width) as u64,
            "ufromfp" => fl::ufromfp(xd, mode, width),
            "ufromfpx" => fl::ufromfpx(xd, mode, width),
            "ufromfpf" => fl::ufromfpf(xf, mode, width),
            "ufromfpxf" => fl::ufromfpxf(xf, mode, width),
            other => panic!("unknown fn {other}"),
        }
    }
}

#[test]
fn fromfp_family_matches_glibc_integer_abi() {
    let mut fails = Vec::new();
    for &(name, xbits, _is_f32, mode, width, want_bits, want_flags) in GOLDEN {
        unsafe { feclearexcept(FE_INVALID | FE_INEXACT) };
        let got = call_fl(name, xbits, mode, width);
        let raised = unsafe { fetestexcept(FE_INVALID | FE_INEXACT) };
        let got_flags = (if raised & FE_INVALID != 0 { 1 } else { 0 })
            | (if raised & FE_INEXACT != 0 { 2 } else { 0 });
        if got != want_bits || got_flags != want_flags {
            if fails.len() < 40 {
                fails.push(format!(
                    "{name}(x={xbits:#018x}, mode={mode}, width={width}): got value={got:#018x} flags={got_flags}, want value={want_bits:#018x} flags={want_flags}"
                ));
            }
        }
    }
    assert!(
        fails.is_empty(),
        "fromfp family diverged from glibc on {}+ tuples:\n{}",
        fails.len(),
        fails.join("\n")
    );
}
